INSERT INTO `category` VALUES (1,'Action','An action game emphasizes physical challenges, including handвҖ“eye coordination and reaction-time'),(2,'RPG','A role-playing game (RPG) is a game in which each participant assumes the role of a character, that can interact within the game\'s imaginary world.'),(3,'MMO','Massively Multiplayer Online game: any online video game in which a player interacts with a large number of other players.'),(4,'FPS','First-Person Shooter: a player aims and shoots at targets, and the graphics displayed are seen from the viewpoint of the shooter'),(6,'Fantasy','Fantasy is a genre of speculative fiction involving magical elements, typically set in a fictional universe and usually inspired by mythology and folklore.'),(11,'Open World','Open world is a virtual world in which the player can approach objectives freely, as opposed to a world with more linear and structured gameplay.'),(12,'Fighting','A fighting game is a genre of video game that involves combat between two or more characters. Fighting game combat often features mechanics such as blocking, grappling, counter-attacking, and chaining attacks together into \"combos');
/*!40000 ALTER TABLE `category` ENABLE KEYS */;
